Bash(send-notification.js << 'EOF'
require\('dotenv'\).config\(\);
const User = require\('./models/User'\);
const mongoose = require\('mongoose'\);
const webpush = require\('web-push'\);

// Set VAPID details
webpush.setVapidDetails\(
    'mailto:support@sugamgarbh.com',
    process.env.PUBLIC_VAPID_KEY,
    process.env.PRIVATE_VAPID_KEY
\);

async function sendTestNotifications\(\) {
    try {
        // Connect to MongoDB
        await mongoose.connect\(process.env.MONGODB_URI\);
        console.log\('✓ Connected to MongoDB'\);

        // Find all active users with push subscriptions
        const users = await User.find\({ 
            isActive: true, 
            webPushSubscription: { $exists: true, $ne: null }
        }\);

        console.log\(`Found ${users.length} users with push subscriptions\\n`\);

        if \(users.length === 0\) {
            console.log\('⚠️ No users registered for push notifications yet.'\);
            console.log\('Please register on the chat page and allow notifications first.'\);
            await mongoose.connection.close\(\);
            return;
        }

        // Send notifications to each user
        for \(const user of users\) {
            const language = user.language || 'hindi';
            const payload = {
                title: language === 'english' ? 'Daily Health Check' : 'दैनिक स्वास्थ्य जांच',
                body: language === 'english' 
                    ? `🌸 Good morning ${user.firstName}! How are you feeling today?`
                    : `🌸 शुभ प्रभात ${user.firstName}! आज आप कैसा महसूस कर रही हैं?`,
                url: '/chat'
            };

            try {
                await webpush.sendNotification\(
                    user.webPushSubscription,
                    JSON.stringify\(payload\)
                \);
                console.log\(`✅ Notification sent to ${user.firstName} \(${language}\)`\);
            } catch \(error\) {
                console.log\(`❌ Failed for ${user.firstName}:`, error.message\);
            }
        }

        console.log\('\\n✓ Notification sending completed!'\);
        await mongoose.connection.close\(\);
    } catch \(error\) {
        console.error\('Error:', error.message\);
        process.exit\(1\);
    }
}

sendTestNotifications\(\);
EOF)

